-- Migration: Seed 2 Eras, 25 Events, 30 Characters and 20 Artifacts of the CHRONOS ecosystem
-- Description: Completa a matriz de dados reais do Knowledge Engine para a validação da busca global.
-- Sprint: 5.2.0
-- Date: 19/07/2026
-- Author: Equipe de Engenharia CHRONOS

BEGIN;

-- 1. Criação da tabela 'artifacts' caso não exista para compatibilidade local
CREATE TABLE IF NOT EXISTS artifacts (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    slug VARCHAR(255) NOT NULL UNIQUE,
    name VARCHAR(255) NOT NULL,
    short_name VARCHAR(255),
    description TEXT NOT NULL,
    summary TEXT,
    artifact_type VARCHAR(100) NOT NULL,
    origin_civilization_id UUID,
    origin_location_id UUID,
    estimated_year INTEGER NOT NULL DEFAULT 0,
    material VARCHAR(255),
    current_location VARCHAR(255),
    cover_image_url TEXT,
    publication_status VARCHAR(50) NOT NULL DEFAULT 'published',
    ativo BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ DEFAULT now() NOT NULL,
    updated_at TIMESTAMPTZ DEFAULT now() NOT NULL
);

-- 2. Inserção de 2 Eras Adicionais (Totalizando 10 Eras)
ON CONFLICT (slug) DO UPDATE SET
    nome = EXCLUDED.nome,
    titulo_curto = EXCLUDED.titulo_curto,
    descricao = EXCLUDED.descricao,
    descricao_resumida = EXCLUDED.descricao_resumida,
    inicio_ano = EXCLUDED.inicio_ano,
    fim_ano = EXCLUDED.fim_ano,
    ordem_cronologica = EXCLUDED.ordem_cronologica,
    cor_hex = EXCLUDED.cor_hex,
    icon_key = EXCLUDED.icon_key,
    publication_status = EXCLUDED.publication_status,
    ativo = EXCLUDED.ativo,
    updated_at = now();

-- 3. Inserção de 23 Eventos Históricos Adicionais (Totalizando 48 Eventos junto com os existentes)
-- Nota: Removidos eventos duplicados que já existem na migration 20260718000002_seed_historical_events.sql:
-- - queda-de-constantinopla (já existe)
-- - batalha-de-maratona (já existe)
ON CONFLICT (id) DO NOTHING;

-- 4. Inserção de 30 Personagens Históricos reais
ON CONFLICT (id) DO NOTHING;

-- 5. Inserção de 20 Artefatos Históricos reais
ON CONFLICT (id) DO NOTHING;

COMMIT;
