('20000000-0000-0000-0000-000000000001', 'batalha-de-termopilas', (SELECT id FROM eras WHERE slug = 'antiguidade-classica' LIMIT 1), 'Batalha das Termópilas', 'Termópilas', 'Famoso confronto militar onde 300 espartanos liderados pelo rei Leônidas resistiram bravamente ao colossal império persa.', 'Confronto épico entre espartanos e persas.', 'military', -480, -480, 5, 'published', true),
('20000000-0000-0000-0000-000000000002', 'incendio-de-roma', (SELECT id FROM eras WHERE slug = 'antiguidade-classica' LIMIT 1), 'Grande Incêndio de Roma', 'Incêndio de Roma', 'Devastador incêndio florestal e urbano que consumiu grande parte da capital imperial romana sob o reinado de Nero.', 'Incêndio que destruiu grande parte de Roma.', 'other', 64, 64, 4, 'published', true),
('20000000-0000-0000-0000-000000000003', 'coroacao-de-carlos-magno', (SELECT id FROM eras WHERE slug = 'idade-media' LIMIT 1), 'Coroação de Carlos Magno', 'Carlos Magno', 'O papa Leão III coroa o rei franco como Imperador do Sacro Império Romano-Germânico, restaurando a governança imperial cristã na Europa.', 'Fundação do Sacro Império Romano-Germânico.', 'political', 800, 800, 5, 'published', true),
('20000000-0000-0000-0000-000000000005', 'invencao-da-prensa-movel', (SELECT id FROM eras WHERE slug = 'renascimento' LIMIT 1), 'Invenção da Prensa Móvel', 'Prensa Móvel', 'Johannes Gutenberg desenvolve o método mecânico de impressão em tipos móveis metálicos, democratizando o acesso cultural.', 'Revolução na impressão e disseminação do conhecimento.', 'scientific', 1440, 1440, 5, 'published', true),
('20000000-0000-0000-0000-000000000006', 'chegada-de-colombo-america', (SELECT id FROM eras WHERE slug = 'idade-moderna' LIMIT 1), 'Chegada de Colombo à América', 'Descoberta da América', 'A expedição espanhola liderada pelo navegador genovês Cristóvão Colombo aporta nas ilhas caribenhas, abrindo a era das navegações transoceânicas.', 'Primeiro contato europeu com as Américas.', 'other', 1492, 1492, 5, 'published', true),
('20000000-0000-0000-0000-000000000007', 'tomada-da-bastilha', (SELECT id FROM eras WHERE slug = 'idade-moderna' LIMIT 1), 'Tomada da Bastilha (Revolução Francesa)', 'Revolução Francesa', 'Levante popular contra o absolutismo monárquico de Luís XVI, proclamando os ideais democráticos universais.', 'Início da Revolução Francesa.', 'political', 1789, 1799, 5, 'published', true),
('20000000-0000-0000-0000-000000000008', 'batalha-de-waterloo', (SELECT id FROM eras WHERE slug = 'revolucao-industrial' LIMIT 1), 'Batalha de Waterloo', 'Waterloo', 'Derrota militar definitiva do imperador francês Napoleão Bonaparte pela coalizão britânica-prussiana na Bélgica.', 'Fim definitivo das guerras napoleônicas.', 'military', 1815, 1815, 5, 'published', true),
('20000000-0000-0000-0000-000000000009', 'eclosao-primeira-guerra-mundial', (SELECT id FROM eras WHERE slug = 'idade-contemporanea' LIMIT 1), 'Eclosão da Primeira Guerra Mundial', 'Primeira Guerra Mundial', 'Assassinato do herdeiro austríaco desencadeia o primeiro conflito industrial militar de escala global.', 'Conflito global de 1914-1918.', 'military', 1914, 1918, 5, 'published', true),
('20000000-0000-0000-0000-000000000010', 'pouso-apollo-11-lua', (SELECT id FROM eras WHERE slug = 'era-espacial' LIMIT 1), 'Pouso da Apollo 11 na Lua', 'Apollo 11', 'Os astronautas americanos Neil Armstrong e Buzz Aldrin tornam-se as primeiras pessoas a caminhar sobre solo extraterrestre.', 'Primeira missão humana bem-sucedida à Lua.', 'scientific', 1969, 1969, 5, 'published', true),
('20000000-0000-0000-0000-000000000012', 'tratado-de-tordesilhas', (SELECT id FROM eras WHERE slug = 'idade-moderna' LIMIT 1), 'Assinatura do Tratado de Tordesilhas', 'Tratado de Tordesilhas', 'Portugal e Espanha dividem as terras do novo mundo marítimo descoberto por uma linha imaginária oceânica.', 'Divisão do Novo Mundo entre Portugal e Espanha.', 'political', 1494, 1494, 4, 'published', true),
('20000000-0000-0000-0000-000000000013', 'fundacao-de-constantinopla', (SELECT id FROM eras WHERE slug = 'antiguidade-classica' LIMIT 1), 'Fundação de Constantinopla', 'Constantinopla', 'Imperador romano Constantino declara a antiga cidade de Bizâncio como a nova capital cristã unificada do império.', 'Nova capital do Império Romano.', 'political', 330, 330, 4, 'published', true),
('20000000-0000-0000-0000-000000000014', 'batalha-de-hastings', (SELECT id FROM eras WHERE slug = 'idade-media' LIMIT 1), 'Batalha de Hastings', 'Hastings', 'Guilherme, o Conquistador normando, derrota o rei Haroldo, assumindo a coroa e moldando o feudalismo britânico.', 'Conquista normanda da Inglaterra.', 'military', 1066, 1066, 5, 'published', true),
('20000000-0000-0000-0000-000000000015', 'edito-de-milao', (SELECT id FROM eras WHERE slug = 'antiguidade-classica' LIMIT 1), 'Édito de Milão', 'Édito de Milão', 'Acordo entre imperadores Constantino e Licínio que concede total liberdade religiosa para os cristãos no império romano.', 'Legalização do cristianismo no Império Romano.', 'religious', 313, 313, 4, 'published', true),
