('20000000-0000-0000-0000-000000000017', 'assassinato-de-julio-cesar', (SELECT id FROM eras WHERE slug = 'antiguidade-classica' LIMIT 1), 'Assassinato de Júlio César', 'Idos de Março', 'Grupo de senadores romanos liderados por Brutus conspira e assassina o ditador perpétuo nos idos de Março.', 'Fim da República Romana.', 'political', -44, -44, 5, 'published', true),
