('20000000-0000-0000-0000-000000000020', 'publicacao-principia', (SELECT id FROM eras WHERE slug = 'idade-moderna' LIMIT 1), 'Publicação do Principia de Newton', 'Principia', 'Isaac Newton lança a obra matemática que estabelece as três leis universais da física e a gravitação cósmica.', 'Fundação da física clássica.', 'scientific', 1687, 1687, 5, 'published', true),
