('20000000-0000-0000-0000-000000000024', 'lancamento-sputnik-1', (SELECT id FROM eras WHERE slug = 'era-espacial' LIMIT 1), 'Lançamento do Sputnik 1', 'Sputnik 1', 'União Soviética coloca em órbita com sucesso o primeiro objeto artificial terrestre, inaugurando oficialmente a corrida cósmica.', 'Início da Era Espacial.', 'scientific', 1957, 1957, 5, 'published', true),
